import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const Checkout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    program: '',
    paymentMethod: 'credit-card',
    cardNumber: '',
    expiryDate: '',
    cvv: '',
    promoCode: '',
    agreeTerms: false
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [discount, setDiscount] = useState(0);
  const [isValidPromo, setIsValidPromo] = useState(false);

  // Determine program details based on URL
  const getProgramDetails = () => {
    const path = location.pathname;
    if (path.includes('data-science-ai')) {
      return {
        name: 'Data Science & AI Program',
        price: '$2,999',
        duration: '6 months',
        type: 'full',
        color: '#667eea'
      };
    } else if (path.includes('cyber-security')) {
      return {
        name: 'Cyber Security & Ethical Hacking Program',
        price: '$2,999',
        duration: '6 months',
        type: 'full',
        color: '#e74c3c'
      };
    } else if (path.includes('devops')) {
      return {
        name: 'DevOps & Cloud Computing Program',
        price: '$2,999',
        duration: '6 months',
        type: 'full',
        color: '#ff6b35'
      };
    } else if (path.includes('data-science-ai-short-term')) {
      return {
        name: 'Data Science & AI Short Term Program',
        price: '$499',
        duration: '4 months',
        type: 'short-term',
        color: '#667eea'
      };
    } else if (path.includes('cyber-security-short-term')) {
      return {
        name: 'Cyber Security & Ethical Hacking Short Term Program',
        price: '$499',
        duration: '4 months',
        type: 'short-term',
        color: '#e74c3c'
      };
    } else if (path.includes('devops-short-term')) {
      return {
        name: 'DevOps & Cloud Computing Short Term Program',
        price: '$999',
        duration: '4 months',
        type: 'short-term',
        color: '#ff6b35'
      };
    }
    return {
      name: 'Program Enrollment',
      price: '$2,999',
      duration: '6 months',
      type: 'full',
      color: '#007bff'
    };
  };

  const program = getProgramDetails();

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handlePromoCodeApply = () => {
    // Simple promo code validation (you can expand this with actual promo codes)
    const validPromoCodes = {
      'SAVE10': 10,
      'SAVE20': 20,
      'STUDENT50': 50,
      'EARLYBIRD': 15,
      'WELCOME100': 100
    };

    const code = formData.promoCode.toUpperCase().trim();
    if (validPromoCodes[code]) {
      setDiscount(validPromoCodes[code]);
      setIsValidPromo(true);
    } else {
      setDiscount(0);
      setIsValidPromo(false);
    }
  };

  const calculateFinalPrice = () => {
    const originalPrice = parseInt(program.price.replace('$', ''));
    const discountAmount = (originalPrice * discount) / 100;
    const finalPrice = originalPrice - discountAmount;
    return {
      original: originalPrice,
      discount: discountAmount,
      final: finalPrice,
      display: `$${finalPrice}`
    };
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);

    // Simulate payment processing
    setTimeout(() => {
      setIsProcessing(false);
      alert('Payment processed successfully! You will receive a confirmation email shortly.');
      navigate('/');
    }, 2000);
  };

  return (
    <div className="checkout-page" style={{ minHeight: '100vh', paddingTop: '100px' }}>
      <div className="container">
        <div style={{ maxWidth: '1200px', margin: '0 auto', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px' }}>

          {/* Program Summary */}
          <div style={{
            background: 'white',
            padding: '40px',
            borderRadius: '15px',
            boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
            height: 'fit-content'
          }}>
            <h2 style={{ fontSize: '28px', fontWeight: '700', marginBottom: '30px', color: '#333' }}>
              Program Summary
            </h2>

            <div style={{
              background: `linear-gradient(135deg, ${program.color} 0%, ${program.color}dd 100%)`,
              color: 'white',
              padding: '30px',
              borderRadius: '10px',
              textAlign: 'center',
              marginBottom: '30px'
            }}>
              <h3 style={{ fontSize: '20px', fontWeight: '600', marginBottom: '10px', margin: 0 }}>
                {program.name}
              </h3>
              <div style={{ fontSize: '16px', marginBottom: '10px' }}>
                <i className="fas fa-clock" style={{ marginRight: '8px' }}></i>
                Duration: {program.duration}
              </div>
              <div style={{ fontSize: '16px', marginBottom: '10px' }}>
                <i className="fas fa-tag" style={{ marginRight: '8px' }}></i>
                Type: {program.type === 'short-term' ? 'Short Term' : 'Full Program'}
              </div>
              <div style={{ fontSize: '24px', fontWeight: '700', marginTop: '15px' }}>
                {program.price}
              </div>
            </div>

            <div style={{ marginTop: '30px' }}>
              <h4 style={{ fontSize: '18px', fontWeight: '600', marginBottom: '20px', color: '#333' }}>
                What's Included:
              </h4>
              <ul style={{ listStyle: 'none', padding: 0 }}>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>Microsoft Certification</span>
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>Lifetime Access to Learning Materials</span>
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>1:1 Mentorship Sessions</span>
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>Capstone Projects</span>
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>100% Job Placement Assistance</span>
                </li>
                <li style={{ display: 'flex', alignItems: 'center', marginBottom: '15px', color: '#666' }}>
                  <i className="fas fa-check-circle" style={{ color: program.color, marginRight: '12px' }}></i>
                  <span>Industry-Recognized Certificate</span>
                </li>
              </ul>
            </div>
          </div>

          {/* Payment Form */}
          <div style={{
            background: 'white',
            padding: '40px',
            borderRadius: '15px',
            boxShadow: '0 10px 30px rgba(0,0,0,0.1)'
          }}>
            <h2 style={{ fontSize: '28px', fontWeight: '700', marginBottom: '30px', color: '#333' }}>
              Complete Your Enrollment
            </h2>

            <form onSubmit={handleSubmit}>
              {/* Personal Information */}
              <div style={{ marginBottom: '30px' }}>
                <h3 style={{ fontSize: '20px', fontWeight: '600', marginBottom: '20px', color: '#333' }}>
                  Personal Information
                </h3>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '20px' }}>
                  <div>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                      First Name *
                    </label>
                    <input
                      type="text"
                      name="firstName"
                      value={formData.firstName}
                      onChange={handleInputChange}
                      required
                      style={{
                        width: '100%',
                        padding: '12px',
                        border: '1px solid #ddd',
                        borderRadius: '5px',
                        fontSize: '14px'
                      }}
                    />
                  </div>

                  <div>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                      Last Name *
                    </label>
                    <input
                      type="text"
                      name="lastName"
                      value={formData.lastName}
                      onChange={handleInputChange}
                      required
                      style={{
                        width: '100%',
                        padding: '12px',
                        border: '1px solid #ddd',
                        borderRadius: '5px',
                        fontSize: '14px'
                      }}
                    />
                  </div>
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                    Email Address *
                  </label>
                  <input
                    type="email"
                    name="email"
                    value={formData.email}
                    onChange={handleInputChange}
                    required
                    style={{
                      width: '100%',
                      padding: '12px',
                      border: '1px solid #ddd',
                      borderRadius: '5px',
                      fontSize: '14px'
                    }}
                  />
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                    Phone Number *
                  </label>
                  <input
                    type="tel"
                    name="phone"
                    value={formData.phone}
                    onChange={handleInputChange}
                    required
                    style={{
                      width: '100%',
                      padding: '12px',
                      border: '1px solid #ddd',
                      borderRadius: '5px',
                      fontSize: '14px'
                    }}
                  />
                </div>
              </div>

              {/* Payment Information */}
              <div style={{ marginBottom: '30px' }}>
                <h3 style={{ fontSize: '20px', fontWeight: '600', marginBottom: '20px', color: '#333' }}>
                  Payment Information
                </h3>

                <div style={{ marginBottom: '20px' }}>
                  <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                    Payment Method
                  </label>
                  <select
                    name="paymentMethod"
                    value={formData.paymentMethod}
                    onChange={handleInputChange}
                    style={{
                      width: '100%',
                      padding: '12px',
                      border: '1px solid #ddd',
                      borderRadius: '5px',
                      fontSize: '14px'
                    }}
                  >
                    <option value="credit-card">Credit Card</option>
                    <option value="debit-card">Debit Card</option>
                    <option value="paypal">PayPal</option>
                    <option value="bank-transfer">Bank Transfer</option>
                  </select>
                </div>

                {(formData.paymentMethod === 'credit-card' || formData.paymentMethod === 'debit-card') && (
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
                    <div>
                      <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                        Card Number *
                      </label>
                      <input
                        type="text"
                        name="cardNumber"
                        value={formData.cardNumber}
                        onChange={handleInputChange}
                        placeholder="1234 5678 9012 3456"
                        required
                        style={{
                          width: '100%',
                          padding: '12px',
                          border: '1px solid #ddd',
                          borderRadius: '5px',
                          fontSize: '14px'
                        }}
                      />
                    </div>

                    <div>
                      <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                        Expiry Date *
                      </label>
                      <input
                        type="text"
                        name="expiryDate"
                        value={formData.expiryDate}
                        onChange={handleInputChange}
                        placeholder="MM/YY"
                        required
                        style={{
                          width: '100%',
                          padding: '12px',
                          border: '1px solid #ddd',
                          borderRadius: '5px',
                          fontSize: '14px'
                        }}
                      />
                    </div>

                    <div>
                      <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500', color: '#333' }}>
                        CVV *
                      </label>
                      <input
                        type="text"
                        name="cvv"
                        value={formData.cvv}
                        onChange={handleInputChange}
                        placeholder="123"
                        required
                        style={{
                          width: '100%',
                          padding: '12px',
                          border: '1px solid #ddd',
                          borderRadius: '5px',
                          fontSize: '14px'
                        }}
                      />
                    </div>
                  </div>
                )}
              </div>

              {/* Terms and Conditions */}
              <div style={{ marginBottom: '30px' }}>
                <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
                  <input
                    type="checkbox"
                    name="agreeTerms"
                    checked={formData.agreeTerms}
                    onChange={handleInputChange}
                    required
                    style={{ marginRight: '10px' }}
                  />
                  <span style={{ fontSize: '14px', color: '#333' }}>
                    I agree to the <a href="#" style={{ color: program.color }}>Terms and Conditions</a> and <a href="#" style={{ color: program.color }}>Privacy Policy</a>
                  </span>
                </label>
              </div>

              {/* Submit Button */}
              <button
                type="submit"
                disabled={isProcessing || !formData.agreeTerms}
                style={{
                  width: '100%',
                  background: isProcessing ? '#ccc' : program.color,
                  color: 'white',
                  padding: '15px',
                  border: 'none',
                  borderRadius: '5px',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: isProcessing ? 'not-allowed' : 'pointer',
                  transition: 'background 0.3s'
                }}
              >
                {isProcessing ? (
                  <span>
                    <i className="fas fa-spinner fa-spin" style={{ marginRight: '8px' }}></i>
                    Processing...
                  </span>
                ) : (
                  <span>
                    <i className="fas fa-lock" style={{ marginRight: '8px' }}></i>
                    Complete Enrollment - {program.price}
                  </span>
                )}
              </button>
            </form>

            {/* Security Badge */}
            <div style={{ textAlign: 'center', marginTop: '20px' }}>
              <div style={{
                display: 'inline-flex',
                alignItems: 'center',
                background: '#f8f9fa',
                padding: '10px 20px',
                borderRadius: '20px',
                fontSize: '12px',
                color: '#666'
              }}>
                <i className="fas fa-shield-alt" style={{ color: '#28a745', marginRight: '8px' }}></i>
                <span>Secure Payment Processing</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;
